exercises.solution:
import numpy as np
from typing import Tuple, Optional

class BitFlippingDecoder:
    def __init__(self, H: np.ndarray, max_iter: int = 50):
        self.H = H
        self.r, self.n = H.shape
        self.max_iter = max_iter

    def syndrome(self, e: np.ndarray) -> np.ndarray:
        return (self.H @ e) % 2

    def count_unsatisfied(self, syn: np.ndarray, pos: int) -> int:
        count = 0
        for i in range(self.r):
            if syn[i] == 1 and self.H[i, pos] == 1:
                count += 1
        return count

    def decode(self, target_syn: np.ndarray) -> Tuple[Optional[np.ndarray], int]:
        e = np.zeros(self.n, dtype=int)
        current_syn = target_syn.copy()

        for it in range(self.max_iter):
            if np.all(current_syn == 0):
                return e, it

            counts = np.array([self.count_unsatisfied(current_syn, i) for i in range(self.n)])
            if np.max(counts) == 0:
                break

            threshold = max(1, int(0.5 * np.max(counts)))
            for i in range(self.n):
                if counts[i] >= threshold:
                    e[i] ^= 1

            current_syn = self.syndrome(e)

        return (e, self.max_iter) if np.all(current_syn == 0) else (None, self.max_iter)
